mapper.select:
SELECT

FROM lease_info t0
left join property_bill propBill on t0.id = propBill.do_id
left join customer_info customerInfo on customerInfo.id = t0.lessee
left join agency agency on agency.id = t0.estimate_id


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.flow_state = #{request.flowState}


    AND t0.lease_term_end BETWEEN

      #{item}



    AND propBill.property_id = #{request.propertyId}


    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.estimate_id = #{request.estimateId}


    AND agency.agency_name LIKE CONCAT('%',#{request.estimateName},'%')


    AND t0.estimate_money = #{request.estimateMoney}


    AND t0.estimate_date = #{request.estimateDate}


    AND t0.estimate_end_date = #{request.estimateEndDate}


    AND t0.agency_fee = #{request.agencyFee}


    AND t0.contacts = #{request.contacts}


    AND t0.contacts_phone = #{request.contactsPhone}


    AND t0.dispose_programme = #{request.disposeProgramme}


    AND t0.month_rent = #{request.monthRent}


    AND t0.year_rent = #{request.yearRent}


    AND t0.margin = #{request.margin}


    AND t0.lease_term_start = #{request.leaseTermStart}


    AND t0.lease_term_end = #{request.leaseTermEnd}


    AND t0.payment_cycle = #{request.paymentCycle}


    AND t0.lessee = #{request.lessee}


    AND customerInfo.customer_name LIKE CONCAT('%',#{request.lesseeName},'%')


    AND t0.remark LIKE CONCAT('%',#{request.remark},'%')


    AND t0.lease_purpose = #{request.leasePurpose}


    AND t0.is_deleted = #{request.isDeleted}


GROUP BY t0.id


    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
